const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const cors = require('cors');

const app = express();

// Security Middleware
app.use(helmet()); // Set security headers
app.use(express.json({ limit: '10kb' })); // Limit payload size
app.use(express.urlencoded({ limit: '10kb', extended: false }));

// CORS Configuration
app.use(cors({
  origin: process.env.ALLOWED_ORIGINS || 'localhost:3000',
  methods: ['GET', 'POST'],
  credentials: true
}));

// Rate Limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // Limit each IP to 100 requests per windowMs
  message: 'Too many requests, please try again later.',
  standardHeaders: true, // Return rate limit info in the `RateLimit-*` headers
  legacyHeaders: false, // Disable the `X-RateLimit-*` headers
});
app.use(limiter);

// Request logging middleware
app.use((req, res, next) => {
  console.log(`${new Date().toISOString()} - ${req.method} ${req.path}`);
  next();
});

// Input validation middleware
const validateQueryParams = (req, res, next) => {
  const allowedParams = ['limit', 'offset'];
  const queryKeys = Object.keys(req.query);

  for (const key of queryKeys) {
    if (!allowedParams.includes(key)) {
      return res.status(400).json({ 
        error: 'Invalid query parameter',
        param: key 
      });
    }
  }

  // Validate limit and offset are numbers
  if (req.query.limit && isNaN(parseInt(req.query.limit, 10))) {
    return res.status(400).json({ error: 'limit must be a number' });
  }
  if (req.query.offset && isNaN(parseInt(req.query.offset, 10))) {
    return res.status(400).json({ error: 'offset must be a number' });
  }

  next();
};

